// MARK: - String Extension for Redaction

extension String {
    func redact() -> String {
        // Simple redaction for tokens and sensitive data
        if self.contains("token") || self.contains("access") || self.contains("secret") {
            return "[REDACTED]"
        }
        return self
    }
